parameters.jsCode:
const input = $json;
const videoData = $('loop-by-video').item.json;

let clips = [];
let engineUsada = '';

if (input.clips && Array.isArray(input.clips)) {
  if (input.clips[0]?.downloadUrl || input.clips[0]?.url) {
    engineUsada = 'opusclip';
    clips = input.clips.map((clip, idx) => ({
      clip_url: clip.downloadUrl || clip.url || '',
      transcricao: clip.transcript || '',
      titulo_sugerido: clip.title || `Clip ${idx + 1}`,
      duracao: clip.duration || 0,
      score: clip.score || clip.viralScore || 0
    }));
  } else {
    engineUsada = 'dumme';
    clips = input.clips.map((clip, idx) => ({
      clip_url: clip.video_url || clip.url || '',
      transcricao: clip.transcription || '',
      titulo_sugerido: clip.suggested_title || `Clip ${idx + 1}`,
      duracao: clip.duration_seconds || 0,
      score: clip.engagement_score || 0
    }));
  }
} else if (input.results && Array.isArray(input.results)) {
  engineUsada = 'dumme';
  clips = input.results.map((clip, idx) => ({
    clip_url: clip.video_url || clip.url || '',
    transcricao: clip.transcription || '',
    titulo_sugerido: clip.suggested_title || `Clip ${idx + 1}`,
    duracao: clip.duration_seconds || 0,
    score: clip.engagement_score || 0
  }));
}

if (clips.length === 0) {
  return [{ json: { has_clips: false } }];
}

const sanitize = (s) => String(s || '').replace(/'/g, "''");

return clips.map(clip => ({
  json: {
    has_clips: true,
    clip_url: clip.clip_url,
    transcricao: clip.transcricao,
    titulo_sugerido: sanitize(clip.titulo_sugerido),
    duracao: clip.duracao,
    score: clip.score,
    engine_usada: engineUsada,
    video_origem_id: videoData.id,
    video_id: videoData.video_id,
    canal_id: videoData.canal_id,
    nome_canal: sanitize(videoData.nome_canal || 'Canal'),
    tom_de_voz: videoData.tom_de_voz || 'informativo e engajante',
    nicho: videoData.nicho || videoData.nicho_alvo || 'geral',
    titulo_original: sanitize(videoData.titulo_original || '')
  }
}));

