parameters.jsCode:
const clipData = $('loop-by-clip').item.json;
const aiRaw = $input.first().json;

let enhanced = {
  titulo_final: clipData.titulo_sugerido || 'Sem título',
  descricao_base: 'Confira este conteúdo!',
  hashtags: ['#shorts', '#viral', '#fy'],
  sugestao_thumbnail: 'IMPERDÍVEL',
  gancho_abertura: ''
};

try {
  let parsed = null;
  if (aiRaw.text) {
    parsed = JSON.parse(aiRaw.text.replace(/```json\n?|```\n?/g, '').trim());
  } else if (aiRaw.output) {
    parsed = typeof aiRaw.output === 'string' ? JSON.parse(aiRaw.output) : aiRaw.output;
  } else if (aiRaw.message?.content) {
    parsed = JSON.parse(aiRaw.message.content);
  } else if (aiRaw.titulo_final) {
    parsed = aiRaw;
  }
  if (parsed) enhanced = { ...enhanced, ...parsed };
} catch (e) {}

const sanitize = (s) => String(s || '').replace(/'/g, "''");

let titulo = enhanced.titulo_final || '';
if (titulo.length > 60) titulo = titulo.substring(0, 57) + '...';

const hashtagsArr = Array.isArray(enhanced.hashtags) ? enhanced.hashtags : ['#shorts'];

return [{
  json: {
    ...clipData,
    titulo_final: sanitize(titulo),
    descricao_base: sanitize(enhanced.descricao_base),
    hashtags: hashtagsArr,
    sugestao_thumbnail: sanitize(enhanced.sugestao_thumbnail),
    gancho_abertura: sanitize(enhanced.gancho_abertura || ''),
    titulo_length: titulo.length,
    hashtag_count: hashtagsArr.length
  }
}];

const clipData = $('if-valid-ai-content').item.json;
const links = $input.all();

let blocoMonetizacao = '';

if (links && links.length > 0 && links[0].json.url) {
  blocoMonetizacao = '\n\n---';
  for (const link of links) {
    const l = link.json;
    if (!l.url) continue;
    const emoji = l.tipo === 'amazon' ? '📚' : 
                  l.tipo === 'hotmart' ? '🎓' : 
                  l.tipo === 'produto_proprio' ? '🚀' : '🔗';
    blocoMonetizacao += `\n${emoji} ${l.descricao_curta}: ${l.url}`;
  }
}

const hashtagsStr = clipData.hashtags
  .map(h => h.startsWith('#') ? h : `#${h}`)
  .join(' ');

const descricaoFinal = `${clipData.descricao_base}${blocoMonetizacao}\n\n${hashtagsStr}`;

const sanitize = (s) => String(s || '').replace(/'/g, "''");

return [{
  json: {
    ...clipData,
    descricao_final: sanitize(descricaoFinal),
    hashtags_str: sanitize(hashtagsStr),
    links_incluidos: links.filter(l => l.json.url).length
  }
}];

const clipId = $('save-clip-to-db').item.json.id;
const clipData = $('build-final-description').item.json;
const configRaw = $json;

const config = {
  publicar_youtube: configRaw.publicar_youtube ?? true,
  publicar_tiktok: configRaw.publicar_tiktok ?? false,
  publicar_instagram: configRaw.publicar_instagram ?? false,
  publicar_facebook: configRaw.publicar_facebook ?? false
};

const plataformas = [];
const platforms = [
  { key: 'publicar_youtube', name: 'youtube' },
  { key: 'publicar_tiktok', name: 'tiktok' },
  { key: 'publicar_instagram', name: 'instagram' },
  { key: 'publicar_facebook', name: 'facebook' }
];

for (const p of platforms) {
  if (config[p.key]) {
    plataformas.push({
      plataforma: p.name,
      clip_id: clipId,
      clip_url: clipData.clip_url,
      titulo: clipData.titulo_final,
      descricao: clipData.descricao_final
    });
  }
}

if (plataformas.length === 0) {
  plataformas.push({
    plataforma: 'youtube',
    clip_id: clipId,
    clip_url: clipData.clip_url,
    titulo: clipData.titulo_final,
    descricao: clipData.descricao_final
  });
}

return plataformas.map(p => ({ json: p }));

